class Solution(object):
    def maxTotalValue(self, nums, k):
        # The value of a subarray = max - min.
        # The maximum value of any subarray is (global_max - global_min).
        # We can choose the same subarray k times, so answer = k * (global_max - global_min).
        return k * (max(nums) - min(nums))
